  ami           = "ami-0c55b159cbfafe1f0"
  instance_type = "c5.large"

  root_block_device {
    volume_type = "gp2"
    volume_size = 20
    encrypted   = true
  }

  tags = {
    Name        = "api-server-01"
    Environment = "production"
    FinOpsAction = "DOWNSIZE"
    FinOpsReviewed = "true"
  }
}

